export function getMateriel406Item(code: string): Materiel406Item | null {
  return MATERIEL_406_ITEMS.find((i) => i.code === code) || null;
}

export function searchMateriel406(query: string): Materiel406Item[] {
  const q = query.trim().toLowerCase();
  if (!q) return MATERIEL_406_ITEMS;
  return MATERIEL_406_ITEMS.filter((i) =>
    i.code.toLowerCase().includes(q) || i.name.toLowerCase().includes(q)
  );
}
